using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class TicketClassifierService
{
    private readonly MLContext _mlContext;
    private readonly string _dataPath;
    private readonly string _modelPath;
    private PredictionEngine<TicketData, TicketPrediction>? _predictionEngine;
    private string[] _categoryLabels = [];

    public bool IsTrained => _predictionEngine is not null;

    public TicketClassifierService(IWebHostEnvironment env)
    {
        _mlContext = new MLContext(seed: 0);
        _dataPath = Path.Combine(env.ContentRootPath, "Data", "tickets.csv");
        _modelPath = Path.Combine(env.ContentRootPath, "Data", "model.zip");
    }

    public EvaluationResult TrainAndEvaluate()
    {
        var data = _mlContext.Data.LoadFromTextFile<TicketData>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var pipeline = _mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketData.Category))
            .Append(_mlContext.Transforms.Text.FeaturizeText("SubjectFeaturized", nameof(TicketData.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText("DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .Append(_mlContext.Transforms.NormalizeMinMax("Features"))
            .Append(_mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy())
            .Append(_mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        // With a small dataset, train on all data and evaluate on the same set
        // to report metrics; in production use cross-validation or a held-out split.
        var model = pipeline.Fit(data);
        var predictions = model.Transform(data);

        var metrics = _mlContext.MulticlassClassification.Evaluate(predictions);

        // Persist model and build prediction engine
        _mlContext.Model.Save(model, data.Schema, _modelPath);
        _predictionEngine = _mlContext.Model.CreatePredictionEngine<TicketData, TicketPrediction>(model);

        // Cache category labels from the key-value mapping
        var labelColumn = predictions.Schema["Label"];
        VBuffer<ReadOnlyMemory<char>> keyValues = default;
        labelColumn.GetKeyValues(ref keyValues);
        _categoryLabels = keyValues.DenseValues().Select(v => v.ToString()).ToArray();

        return new EvaluationResult
        {
            MacroAccuracy = (float)metrics.MacroAccuracy,
            MicroAccuracy = (float)metrics.MicroAccuracy,
            LogLoss = (float)metrics.LogLoss,
            LogLossReduction = (float)metrics.LogLossReduction
        };
    }

    public PredictionResult Predict(TicketRequest request)
    {
        if (_predictionEngine is null)
            throw new InvalidOperationException("Model has not been trained. Call POST /api/model/train first.");

        var input = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionEngine.Predict(input);

        var confidence = new Dictionary<string, float>();
        for (var i = 0; i < _categoryLabels.Length && i < prediction.Score.Length; i++)
        {
            confidence[_categoryLabels[i]] = prediction.Score[i];
        }

        return new PredictionResult
        {
            PredictedCategory = prediction.Category,
            Confidence = confidence
        };
    }
}

